// // This is a 4-bit down-counter with synchronous reset.
module up_down_counter (
        input clk,
        input up,
        input reset,
        output reg [3:0] q);

    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 4'b0000;
        else if (up)
            q <= q + 1;
        else
            q <= q - 1;
    end

endmodule
